//! Metadata about every UEFI protocol defined in the specification.
//!
//! Includes each protocol's canonical name, GUID, and summary text, and
//! provides a way to look up that information by GUID.

use uguid::Guid;

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub struct UEFIProtocolInfo {
    name: &'static str,
    guid: Guid,
    summary: &'static str,
}
impl UEFIProtocolInfo {
    pub const fn name(&self) -> &'static str {
        self.name
    }
    pub const fn guid(&self) -> Guid {
        self.guid
    }
    pub const fn summary(&self) -> &'static str {
        self.summary
    }
}

macro_rules! define_protocols {
    ($($canonical_name:ident => $uuid:literal => $summary:literal,)*) => {
        $(
            pastey::paste! {
                pub const [< $canonical_name _GUID>]: Guid = uguid::guid!($uuid);
            }

            pub const $canonical_name: UEFIProtocolInfo = UEFIProtocolInfo {
                name: stringify!($canonical_name),
                guid: uguid::guid!($uuid),
                summary: $summary
            };
        )*

        static ALL_PROTOCOLS: &[UEFIProtocolInfo] = &[
            $( $canonical_name, )*
        ];

        impl UEFIProtocolInfo {
            pub const fn by_guid(guid: Guid) -> Option<&'static Self> {
                let b = guid.to_bytes();

                let mut i = 0;
                'protocols: while i < ALL_PROTOCOLS.len() {
                    let a = ALL_PROTOCOLS[i].guid.to_bytes();

                    let mut j = 0;
                    while j < 16 {
                        if a[j] != b[j] {
                            i += 1;
                            continue 'protocols;
                        }
                        j += 1;
                    }

                    return Some(&ALL_PROTOCOLS[i]);
                }

                None
            }
        }
    };
}

