#[cfg(test)]
mod tests {
    use uguid::guid;

    use crate::protocols::{ALL_PROTOCOLS, UEFIProtocolInfo};

    #[test]
    pub fn find_some_protocols() {
        assert_eq!(
            UEFIProtocolInfo::by_guid(guid!("e98adb03-b8b9-4af8-ba20-26e9114cbce5")),
            Some(&super::EFI_USER_CREDENTIAL2_PROTOCOL)
        );
        assert_eq!(
            UEFIProtocolInfo::by_guid(guid!("1a1241e6-8f19-41a9-bc0e-e8ef39e06546")),
            Some(&super::EFI_HII_IMAGE_EX_PROTOCOL)
        );
        assert_eq!(
            UEFIProtocolInfo::by_guid(guid!("05c99a21-c70f-4ad2-8a5f-35df3343f51e")),
            Some(&super::EFI_DEVICE_PATH_FROM_TEXT_PROTOCOL)
        );
        assert_eq!(
            UEFIProtocolInfo::by_guid(guid!("e98adb03-b8b9-4af8-ba20-133713371337")),
            None
        );
        assert!(super::ALL_PROTOCOLS.len() >= 152);

        assert_eq!(
            super::EFI_DEVICE_PATH_FROM_TEXT_PROTOCOL.name,
            "EFI_DEVICE_PATH_FROM_TEXT_PROTOCOL"
        );
    }

    #[test]
    pub fn rule_out_parsing_mistakes() {
        for protocol in ALL_PROTOCOLS {
            assert!(!protocol.name.contains(" "));
            assert!(!protocol.summary.contains("ref:"));
        }
    }
}
